	if len(d.Entries) != 2 {
		t.Fatalf("expected 2 digest entries, got %d", len(d.Entries))
	}
	if d.Entries["k1"].Version != 1 || d.Entries["k2"].Version != 2 {
		t.Fatal("version mismatch in digest")
	}
}

func TestStateStore_Diff(t *testing.T) {
