	if a.Hash() != b.Hash() {
		t.Fatal("identical state should produce identical hash")
	}
}

func TestStateStore_HashDiffers(t *testing.T) {
	a := NewStateStore("n1")
	a.Put("k1", []byte("v1"))
	b := NewStateStore("n2")
