		t.Fatal("entry mismatch")
	}
}

func TestStateStore_ThreadSafety(t *testing.T) {
	s := NewStateStore("n1")
	var wg sync.WaitGroup
	for i := 0; i < 50; i++ {
		wg.Add(1)
		i := i
		go func() {
			defer wg.Done()
			key := fmt.Sprintf("key-%d", i)
			s.Put(key, []byte(fmt.Sprintf("val-%d", i)))
		}()
	}
	wg.Wait()
	if s.Len() != 50 {
		t.Fatalf("expected 50, got %d", s.Len())
	}
}

